mapper.select:
SELECT player_id AS playerId, player_name AS playerName, jersey_number AS jerseyNumber, team_id AS teamId, team_name AS teamName, tournament_id AS tournamentId, sport_type AS sportType, sport_type_name AS sportTypeName, match_played AS matchPlayed, total_goals AS totalGoals, total_assists AS totalAssists, total_yellow_cards AS totalYellowCards, total_red_cards AS totalRedCards, total_fouls AS totalFouls, total_play_time AS totalPlayTime, avg_play_time AS avgPlayTime, total_score AS totalScore FROM v_player_tournament_stats
AND tournament_id = #{tournamentId} AND team_id = #{teamId}
ORDER BY total_score DESC

mapper.update:
UPDATE match_player
sport_type = #{sportType}, player_id = #{playerId}, status = #{status}, play_time = #{playTime},
WHERE id = #{id}
